// ============ CHART GENERATORS ============
export function generatePriceHistory(days: number = 30) {
  // 暂无历史价格数据，返回空数组
  const data: { date: string; price: number; volume: number }[] = [];
  const now = Date.now();
  for (let i = days; i >= 0; i--) {
    data.push({
      date: new Date(now - i * 86400000).toLocaleDateString("zh-CN", { month: "short", day: "numeric" }),
      price: 0,
      volume: 0,
    });
  }
  return data;
}

export function generatePortfolioHistory(days: number = 30) {
  // 暂无资产组合历史数据，返回空数组
  const data: { date: string; value: number; pnl: number }[] = [];
  const now = Date.now();
  for (let i = days; i >= 0; i--) {
    data.push({
      date: new Date(now - i * 86400000).toLocaleDateString("zh-CN", { month: "short", day: "numeric" }),
      value: 0,
      pnl: 0,
    });
  }
  return data;
}

